// signature of a scoring function
type ScoringFn = fn(PreviousScores, CharPair) -> Score;
// make scoring function for a simple scheme
fn simple_subst_scoring(same: Score, mismatch: Score)
-> ScoringFn {
// this lambda expression returns a function
|prev, chars| {
prev.no_gap +
if chars.q == chars.s { same } else { mismatch }
}
}.
